from xhtml2pdf import pisa
from io import BytesIO
from datetime import datetime

def generate_invoice_pdf(invoice, customer, project, items):
    # Calculate totals
    subtotal = sum(item.amount for item in items)
    tax = 0.0 # Placeholder for tax if needed
    total = subtotal + tax
    
    amount_paid = invoice.amount_paid or 0.0
    balance_due = max(0.0, total - amount_paid)

    # Format dates
    issue_date = invoice.issue_date.strftime("%Y-%m-%d") if invoice.issue_date else "-"
    due_date = invoice.due_date.strftime("%Y-%m-%d") if invoice.due_date else "-"

    # Read Boilerplate
    try:
        with open("app/invoice_footer.txt", "r") as f:
            boilerplate = f.read().replace("\n", "<br/>")
    except FileNotFoundError:
        boilerplate = "Thank you for your business!"

    # HTML Template
    # Changes:
    # - Reduced margins (@page margin: 0.5in)
    # - Smaller font size (10px) (9px for table content)
    # - Bill To section: Grid layout with labels, no extra spacing
    # - Compact table with reduced padding
    
    html_content = f"""
    <html>
    <head>
        <style>
            @page {{ size: letter; margin: 0.5in; }}
            body {{ font-family: Helvetica, sans-serif; font-size: 11px; color: #333; line-height: 1.4; }}
            
            .header {{ margin-bottom: 20px; border-bottom: 2px solid #eee; padding-bottom: 10px; }}
            .title {{ font-size: 24px; font-weight: bold; color: #2c3e50; float: left; }}
            .meta {{ float: right; text-align: right; }}
            
            .section-title {{ font-size: 12px; font-weight: bold; color: #7f8c8d; border-bottom: 1px solid #ddd; margin-bottom: 5px; padding-bottom: 2px; }}
            
            /* Three Column Layout for Bill To / Ship To / Details */
            .info-grid {{ width: 100%; margin-bottom: 20px; }}
            .info-col {{ width: 32%; vertical-align: top; padding-right: 5px; word-wrap: break-word; }}
            
            /* Key-Value styles for Bill To */
            .kv-table {{ width: 100%; border-collapse: collapse; }}
            .kv-key {{ width: 80px; color: #7f8c8d; font-weight: bold; padding: 2px 0; vertical-align: top; }}
            .kv-value {{ padding: 2px 0; vertical-align: top; }}
            
            /* Items Table */
            .items-table {{ width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 10px; }}
            .items-table th {{ background-color: #f8f9fa; color: #2c3e50; font-weight: bold; text-align: left; padding: 6px 4px; border-bottom: 2px solid #ddd; }}
            .items-table td {{ padding: 6px 4px; border-bottom: 1px solid #eee; vertical-align: top; }}
            
            .amount {{ text-align: right; white-space: nowrap; }}
            .center {{ text-align: center; }}
            
            .memo {{ color: #666; font-style: italic; font-size: 9px; margin-top: 2px; padding-left: 5px; border-left: 2px solid #eee; }}
            
            .totals {{ margin-top: 20px; float: right; width: 250px; }}
            .total-row {{ padding: 4px 0; }}
            .total-final {{ font-size: 14px; font-weight: bold; border-top: 2px solid #333; margin-top: 5px; padding-top: 5px; }}
            
            .footer {{ margin-top: 40px; text-align: left; color: #7f8c8d; font-size: 9px; border-top: 1px solid #eee; padding-top: 10px; }}
        </style>
    </head>
    <body>
        <table style="width: 100%; border-bottom: 2px solid #eee; margin-bottom: 20px; padding-bottom: 10px;">
            <tr>
                <td style="vertical-align: top;">
                     <div class="title" style="margin-top: 0px;">INVOICE</div>
                     <div style="font-size: 14px; font-weight: bold; margin-top: 5px;">{invoice.invoice_number}</div>

                </td>
                <td style="text-align: right; vertical-align: top;">
                    <!-- Absolute path is required for xhtml2pdf -->
                    <img src="data:image/png;base64," style="height: 98px;" />
                </td>
            </tr>
        </table>

        <table class="info-grid">
            <tr>
                <td class="info-col">
                    <div class="section-title">BILL TO</div>
                    <table class="kv-table">
                        <tr>
                            <td class="kv-key">Company:</td>
                            <td class="kv-value"><strong>{customer.name}</strong></td>
                        </tr>
                        <tr>
                            <td class="kv-key">Project:</td>
                            <td class="kv-value">{project.name}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Address:</td>
                            <td class="kv-value">{customer.address or '-'}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Email:</td>
                            <td class="kv-value">{customer.email or '-'}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Phone:</td>
                            <td class="kv-value">{customer.phone or '-'}</td>
                        </tr>
                    </table>
                </td>
                <td style="width: 2%;"></td> <!-- Spacer -->
                <td class="info-col">
                    <div class="section-title">SHIP TO</div>
                    <table class="kv-table">
                        <tr>
                            <td class="kv-key">Location:</td>
                            <td class="kv-value">{project.location.name if project.location else '-'}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Address:</td>
                            <td class="kv-value">{project.location.address if project.location else '-'}</td>
                        </tr>
                    </table>
                </td>
                <td style="width: 2%;"></td> <!-- Spacer -->
                <td class="info-col">
                    <div class="section-title">DATES & DETAILS</div>
                    <table class="kv-table">
                        <tr>
                            <td class="kv-key">Issue Date:</td>
                            <td class="kv-value">{issue_date}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Due Date:</td>
                            <td class="kv-value">{due_date}</td>
                        </tr>
                         <tr>
                            <td class="kv-key">PO #:</td>
                            <td class="kv-value">{project.customer_po or '-'}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Project #:</td>
                            <td class="kv-value">{project.project_unique_id or '-'}</td>
                        </tr>
                        <tr>
                            <td class="kv-key">Customer PM:</td>
                            <td class="kv-value">{project.customer_pm_user.first_name + ' ' + project.customer_pm_user.last_name if hasattr(project.customer_pm_user, 'first_name') and project.customer_pm_user.first_name else (project.customer_pm_user.username if project.customer_pm_user else '-')}</td>
                        </tr>
                    </table>
                </td>
            </tr>
        </table>

        <table class="items-table">
            <thead>
                <tr>
                    <th style="width: 55%;">Description</th>
                    <th style="width: 10%;" class="center">Qty</th>
                    <th style="width: 15%;" class="amount">Unit Price</th>
                    <th style="width: 20%;" class="amount">Amount</th>
                </tr>
            </thead>
            <tbody>
                {"".join(f'''
                <tr>
                    <td>
                        {item.description}
                        {f'<div class="memo">Memo: {item.memo}</div>' if item.memo else ''}
                    </td>
                    <td class="center">{item.quantity}</td>
                    <td class="amount">${item.unit_price:,.2f}</td>
                    <td class="amount">${item.amount:,.2f}</td>
                </tr>
                ''' for item in items)}
            </tbody>
        </table>

        <table style="width: 300px; margin-top: 20px;" align="right">
            <tr>
                <td style="text-align: left; padding: 4px 0;">Subtotal:</td>
                <td style="text-align: right; padding: 4px 0;">${subtotal:,.2f}</td>
            </tr>
            <!-- Tax would go here -->
            <tr>
                <td style="text-align: left; padding-top: 5px; border-top: 2px solid #333; font-size: 14px; font-weight: bold;">Total:</td>
                <td style="text-align: right; padding-top: 5px; border-top: 2px solid #333; font-size: 14px; font-weight: bold;">${total:,.2f}</td>
            </tr>
            <tr>
                <td style="text-align: left; padding: 4px 0; color: #27ae60;">Amount Paid:</td>
                <td style="text-align: right; padding: 4px 0; color: #27ae60;">${amount_paid:,.2f}</td>
            </tr>
            <tr>
                <td style="text-align: left; padding-top: 5px; border-top: 2px solid #333; font-size: 14px; font-weight: bold; color: {'#c0392b' if balance_due > 0 else '#333'};">Balance Due:</td>
                <td style="text-align: right; padding-top: 5px; border-top: 2px solid #333; font-size: 14px; font-weight: bold; color: {'#c0392b' if balance_due > 0 else '#333'};">${balance_due:,.2f}</td>
            </tr>
        </table>
        
        <div style="clear:both;"></div>

        <div class="footer">
            {boilerplate}
        </div>
    </body>
    </html>
    """

    return html_content

def generate_project_report_pdf(project):
    """Generates a comprehensive PDF report for a project including milestones, tasks, and invoices."""
    issue_date = datetime.utcnow().strftime("%Y-%m-%d")
    
    # Calculate Summaries
    total_budget = project.budget or 0
    total_planned = project.current_value or 0
    total_billed = project.total_billed or 0
    remaining = total_planned - total_billed
    amount_paid = getattr(project, 'amount_paid', 0)
    balance_due = getattr(project, 'balance_due', 0)
    
    # Customer and Lead info
    customer_name = project.customer.name if project.customer else (project.lead.company if project.lead else 'Unknown')
    customer_contact = project.customer.email if project.customer else (project.lead.email if project.lead else '-')
    
    html_content = f"""
    <html>
    <head>
        <style>
            @page {{ size: letter; margin: 0.5in; }}
            body {{ font-family: Helvetica, sans-serif; font-size: 11px; color: #333; line-height: 1.4; }}
            
            .header {{ margin-bottom: 20px; border-bottom: 2px solid #eee; padding-bottom: 10px; }}
            .title {{ font-size: 24px; font-weight: bold; color: #2c3e50; float: left; }}
            
            .section-title {{ font-size: 14px; font-weight: bold; color: #fff; background-color: #2980b9; padding: 4px 8px; margin-top: 20px; margin-bottom: 10px; }}
            
            .info-grid {{ width: 100%; margin-bottom: 15px; }}
            .info-col {{ width: 48%; vertical-align: top; }}
            
            .kv-table {{ width: 100%; border-collapse: collapse; }}
            .kv-key {{ width: 100px; color: #7f8c8d; font-weight: bold; padding: 3px 0; vertical-align: top; }}
            .kv-value {{ padding: 3px 0; vertical-align: top; }}
            
            .data-table {{ width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 10px; }}
            .data-table th {{ background-color: #f8f9fa; color: #2c3e50; font-weight: bold; text-align: left; padding: 6px 4px; border-bottom: 2px solid #ddd; }}
            .data-table td {{ padding: 6px 4px; border-bottom: 1px solid #eee; vertical-align: top; }}
            
            .amount {{ text-align: right; white-space: nowrap; }}
            .center {{ text-align: center; }}
            
            .financial-summary {{ margin-top: 15px; background: #f8f9fa; padding: 10px; border-radius: 4px; border: 1px solid #ddd; }}
        </style>
    </head>
    <body>
        <table style="width: 100%; border-bottom: 2px solid #eee; margin-bottom: 15px; padding-bottom: 10px;">
            <tr>
                <td style="vertical-align: top;">
                     <div class="title" style="margin-top: 0px;">PROJECT STATUS REPORT</div>
                     <div style="font-size: 14px; font-weight: bold; margin-top: 5px;">{project.project_unique_id} - {project.name}</div>
                </td>
                <td style="text-align: right; vertical-align: top;">
                    <img src="data:image/png;base64," style="height: 81px;" />
                    <div style="font-size: 10px; color: #7f8c8d; margin-top: 5px;">Generated: {issue_date}</div>
                </td>
            </tr>
        </table>

        <!-- Overview Section -->
        <div class="section-title">PROJECT OVERVIEW</div>
        <table class="info-grid">
            <tr>
                <td class="info-col">
                    <table class="kv-table">
                        <tr><td class="kv-key">Status:</td><td class="kv-value" style="text-transform: capitalize;"><strong>{project.status.value if hasattr(project.status, 'value') else str(project.status).replace('ProjectStatus.', '')}</strong></td></tr>
                        <tr><td class="kv-key">Client:</td><td class="kv-value">{customer_name}</td></tr>
                        <tr><td class="kv-key">Contact:</td><td class="kv-value">{customer_contact}</td></tr>
                        <tr><td class="kv-key">Project Manager:</td><td class="kv-value">{project.pm_user.username if project.pm_user else '-'}</td></tr>
                    </table>
                </td>
                <td style="width: 4%;"></td>
                <td class="info-col">
                    <table class="kv-table">
                        <tr><td class="kv-key">Start Date:</td><td class="kv-value">{project.created_at.strftime("%Y-%m-%d") if project.created_at else '-'}</td></tr>
                        <tr><td class="kv-key">Target End:</td><td class="kv-value">{project.due_date.strftime("%Y-%m-%d") if project.due_date else 'TBD'}</td></tr>
                        <tr><td class="kv-key">PO Number:</td><td class="kv-value">{project.customer_po or '-'}</td></tr>
                        <tr><td class="kv-key">Progress:</td><td class="kv-value">{round(project.financial_progress or 0)}%</td></tr>
                    </table>
                </td>
            </tr>
        </table>

        <div class="section-title">FINANCIAL SUMMARY</div>
        <table class="data-table">
            <tr>
                <th>Estimated Budget</th>
                <th>Planned Value (Actual)</th>
                <th>Total Billed</th>
                <th>Remaining unbilled</th>
                <th>Amount Paid</th>
                <th>Balance Due</th>
            </tr>
            <tr>
                <td>${total_budget:,.2f}</td>
                <td>${total_planned:,.2f}</td>
                <td style="color: #27ae60;">${total_billed:,.2f}</td>
                <td style="color: {'#c0392b' if remaining < 0 else '#333'};">${remaining:,.2f}</td>
                <td style="color: #2980b9;">${amount_paid:,.2f}</td>
                <td style="color: {'#c0392b' if balance_due > 0 else '#333'};">${balance_due:,.2f}</td>
            </tr>
        </table>
        
        <!-- Milestones & Tasks -->
        <div class="section-title">MILESTONES & TASKS</div>
        """
        
    if not project.milestones:
        html_content += "<p style='color: #7f8c8d; font-style: italic;'>No milestones defined for this project.</p>"
    else:
        for m in sorted(project.milestones, key=lambda x: str(x.milestone_number)):
            m_status = "Billed" if m.invoice_id else ("Completed" if m.is_completed else "In Progress")
            html_content += f"""
            <div style="background-color: #f1f2f6; padding: 6px; margin-top: 15px; border-left: 3px solid #2980b9; font-weight: bold; font-size: 12px;">
                Milestone #{m.milestone_number}: {m.name} 
                <span style="float: right; font-weight: normal; color: #555;">Status: {m_status} | Progress: {round(m.progress or 0)}% | Value: ${m.cost:,.2f}</span>
            </div>
            """
            
            if not m.tasks:
                html_content += "<p style='margin-left: 10px; font-size: 9px; color: #999;'>No tasks assigned to this milestone.</p>"
            else:
                html_content += """
                <table class="data-table" style="margin-top: 0px; margin-left: 10px; width: 98%;">
                    <tr>
                        <th style="width: 40%">Task Description</th>
                        <th style="width: 15%">Assigned To</th>
                        <th style="width: 15%">Status</th>
                        <th style="width: 15%" class="center">Progress</th>
                        <th style="width: 15%" class="center">Hours (Act/Est)</th>
                    </tr>
                """
                for t in m.tasks:
                    assigned = t.assigned_to.username if t.assigned_to else 'Unassigned'
                    hrs_spent = t.total_hours_spent or 0
                    hrs_est = t.estimated_effort or 0
                    status_lbl = t.status.value if hasattr(t.status, 'value') else str(t.status).replace('TaskStatus.', '').replace('_', ' ').title()
                    html_content += f"""
                    <tr>
                        <td>{t.description}</td>
                        <td>{assigned}</td>
                        <td>{status_lbl}</td>
                        <td class="center">{round(t.progress or 0)}%</td>
                        <td class="center">{hrs_spent} / {hrs_est if hrs_est > 0 else '?'}</td>
                    </tr>
                    """
                html_content += "</table>"
                
    # Invoices
    html_content += """
        <div class="section-title">INVOICES ISSUED</div>
    """
    if not project.invoices:
        html_content += "<p style='color: #7f8c8d; font-style: italic;'>No invoices issued for this project.</p>"
    else:
        html_content += """
        <table class="data-table">
            <tr>
                <th>Invoice #</th>
                <th>Issue Date</th>
                <th>Status</th>
                <th class="amount">Amount</th>
                <th class="amount">Paid</th>
                <th class="amount">Balance</th>
            </tr>
        """
        for inv in sorted(project.invoices, key=lambda x: str(x.issue_date), reverse=True):
            issue_d = inv.issue_date.strftime("%Y-%m-%d") if inv.issue_date else "-"
            # sum up lines
            inv_total = sum(li.amount for li in inv.items) if inv.items else 0
            inv_paid = inv.amount_paid or 0.0
            inv_bal = max(0.0, inv_total - inv_paid)
            # note status is enum
            status_str = inv.status.value if hasattr(inv.status, 'value') else str(inv.status).replace('InvoiceStatus.', '')
            html_content += f"""
            <tr>
                <td>{inv.invoice_number}</td>
                <td>{issue_d}</td>
                <td><strong style="text-transform: capitalize;">{status_str}</strong></td>
                <td class="amount">${inv_total:,.2f}</td>
                <td class="amount" style="color:#27ae60;">${inv_paid:,.2f}</td>
                <td class="amount" style="color:{'#c0392b' if inv_bal > 0 else '#333'};">${inv_bal:,.2f}</td>
            </tr>
            """
        html_content += "</table>"

    html_content += """
    </body>
    </html>
    """
    
    return html_content

def generate_task_report_pdf(report, start_date=None, end_date=None, user_info=None, task_type_filter=None):
    """Generates a comprehensive PDF report for task analysis metrics."""
    issue_date = datetime.utcnow().strftime("%Y-%m-%d")
    date_range_str = f"{start_date.strftime('%Y-%m-%d')} to {end_date.strftime('%Y-%m-%d')}" if (start_date and end_date) else "All Time"
    
    html_content = f"""
    <html>
    <head>
        <style>
            @page {{ size: letter; margin: 0.5in; }}
            body {{ font-family: Helvetica, sans-serif; font-size: 11px; color: #333; line-height: 1.4; }}
            
            .header {{ margin-bottom: 20px; border-bottom: 2px solid #eee; padding-bottom: 10px; }}
            .title {{ font-size: 24px; font-weight: bold; color: #2c3e50; float: left; }}
            
            .section-title {{ font-size: 14px; font-weight: bold; color: #fff; background-color: #2980b9; padding: 4px 8px; margin-top: 20px; margin-bottom: 10px; }}
            
            .info-grid {{ width: 100%; margin-bottom: 15px; }}
            .info-col {{ width: 48%; vertical-align: top; }}
            
            .kv-table {{ width: 100%; border-collapse: collapse; }}
            .kv-key {{ width: 100px; color: #7f8c8d; font-weight: bold; padding: 3px 0; vertical-align: top; }}
            .kv-value {{ padding: 3px 0; vertical-align: top; }}
            
            .data-table {{ width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 10px; }}
            .data-table th {{ background-color: #f8f9fa; color: #2c3e50; font-weight: bold; text-align: left; padding: 6px 4px; border-bottom: 2px solid #ddd; }}
            .data-table td {{ padding: 6px 4px; border-bottom: 1px solid #eee; vertical-align: top; }}
            
            .center {{ text-align: center; }}
            .right {{ text-align: right; }}
        </style>
    </head>
    <body>
        <table style="width: 100%; border-bottom: 2px solid #eee; margin-bottom: 15px; padding-bottom: 10px;">
            <tr>
                <td style="vertical-align: top;">
                     <div class="title" style="margin-top: 0px;">TASK ANALYSIS REPORT</div>
                     <div style="font-size: 14px; font-weight: bold; margin-top: 5px;">User: {user_info or "All Users"}</div>
                     {f'<div style="font-size: 14px; font-weight: bold; margin-top: 2px;">Type: {task_type_filter}</div>' if task_type_filter else ''}
                </td>
                <td style="text-align: right; vertical-align: top;">
                    <img src="data:image/png;base64," style="height: 81px;" />
                    <div style="font-size: 10px; color: #7f8c8d; margin-top: 5px;">Generated: {issue_date}</div>
                </td>
            </tr>
        </table>
        
        <div class="section-title">SUMMARY</div>
        <table class="info-grid">
            <tr>
                <td class="info-col">
                    <table class="kv-table">
                        <tr><td class="kv-key">Date Range:</td><td class="kv-value">{date_range_str}</td></tr>
                        <tr><td class="kv-key">Total Hours:</td><td class="kv-value"><strong>{report.total_hours_logged:.1f} hrs</strong></td></tr>
                        <tr><td class="kv-key">Active Tasks:</td><td class="kv-value">{len(report.tasks)}</td></tr>
                    </table>
                </td>
                <td style="width: 4%;"></td>
                <td class="info-col">
                </td>
            </tr>
        </table>
        
        <table style="width: 100%;">
            <tr>
                <td style="width: 32%; vertical-align: top;">
                    <div class="section-title">HOURS BY USER</div>
                    <table class="data-table">
                        <tr>
                            <th>User</th>
                            <th class="right">Hours</th>
                            <th class="right">%</th>
                        </tr>
                        {"".join(f'''
                        <tr>
                            <td>{u.username}</td>
                            <td class="right">{u.hours_logged:.1f}</td>
                            <td class="right">{((u.hours_logged / report.total_hours_logged) * 100) if report.total_hours_logged > 0 else 0:.1f}%</td>
                        </tr>
                        ''' for u in report.by_user) if report.by_user else '<tr><td colspan="3" class="center">No data</td></tr>'}
                    </table>
                </td>
                <td style="width: 2%;"></td>
                <td style="width: 32%; vertical-align: top;">
                    <div class="section-title">HOURS BY TYPE</div>
                    <table class="data-table">
                        <tr>
                            <th>Type</th>
                            <th class="right">Hrs</th>
                            <th class="right">%</th>
                        </tr>
                        {"".join(f'''
                        <tr>
                            <td>{t.task_type}</td>
                            <td class="right">{t.hours_logged:.1f}</td>
                            <td class="right">{((t.hours_logged / report.total_hours_logged) * 100) if report.total_hours_logged > 0 else 0:.1f}%</td>
                        </tr>
                        ''' for t in report.by_type) if report.by_type else '<tr><td colspan="3" class="center">No data</td></tr>'}
                    </table>
                </td>
                <td style="width: 2%;"></td>
                <td style="width: 32%; vertical-align: top;">
                    <div class="section-title">HOURS BY LOCATION</div>
                    <table class="data-table">
                        <tr>
                            <th>Location</th>
                            <th class="right">Hrs</th>
                            <th class="right">%</th>
                        </tr>
                        {"".join(f'''
                        <tr>
                            <td>{l.work_location}</td>
                            <td class="right">{l.hours_logged:.1f}</td>
                            <td class="right">{((l.hours_logged / report.total_hours_logged) * 100) if report.total_hours_logged > 0 else 0:.1f}%</td>
                        </tr>
                        ''' for l in report.by_location) if getattr(report, 'by_location', None) else '<tr><td colspan="3" class="center">No data</td></tr>'}
                    </table>
                </td>
            </tr>
        </table>
        
        <div class="section-title">DETAILED TASK ACTIVITY</div>
        <table class="data-table">
            <tr>
                <th style="width: 40%;">Task</th>
                <th style="width: 15%;">Type</th>
                <th style="width: 15%;">Status</th>
                <th class="right" style="width: 10%;">Period Hrs</th>
                <th class="right" style="width: 10%;">Total Hrs</th>
                <th class="right" style="width: 10%;">Est. Effort</th>
            </tr>
            {"".join(f'''
            <tr>
                <td><strong>#{t.id}</strong> - {t.description[:80] + '...' if len(t.description) > 80 else t.description}</td>
                <td>{t.task_type}</td>
                <td>{t.status}</td>
                <td class="right"><strong>{t.hours_logged:.1f}</strong></td>
                <td class="right">{t.total_hours_spent:.1f}</td>
                <td class="right">{t.estimated_effort:.1f}</td>
            </tr>
            ''' for t in report.tasks) if report.tasks else '<tr><td colspan="6" class="center" style="padding: 20px;">No task activity found in this period.</td></tr>'}
        </table>
        
    </body>
    </html>
    """
    return html_content

def generate_event_report_pdf(report, start_date=None, end_date=None, user_info=None, task_type_filter=None):
    """Generates a comprehensive PDF report for event analysis metrics."""
    issue_date = datetime.utcnow().strftime("%Y-%m-%d")
    date_range_str = f"{start_date.strftime('%Y-%m-%d')} to {end_date.strftime('%Y-%m-%d')}" if (start_date and end_date) else "All Time"
    
    # We stripped the heavy base64 image logo so it doesn't break rendering on pure textual logs.
    html_content = f"""
    <html>
    <head>
        <style>
            @page {{ size: letter; margin: 0.5in; }}
            body {{ font-family: Helvetica, sans-serif; font-size: 11px; color: #333; line-height: 1.4; }}
            
            .header {{ margin-bottom: 20px; border-bottom: 2px solid #eee; padding-bottom: 10px; }}
            .title {{ font-size: 24px; font-weight: bold; color: #2c3e50; float: left; }}
            
            .section-title {{ font-size: 14px; font-weight: bold; color: #fff; background-color: #2980b9; padding: 4px 8px; margin-top: 20px; margin-bottom: 10px; }}
            
            .info-grid {{ width: 100%; margin-bottom: 15px; }}
            .info-col {{ width: 48%; vertical-align: top; }}
            
            .kv-table {{ width: 100%; border-collapse: collapse; }}
            .kv-key {{ width: 100px; color: #7f8c8d; font-weight: bold; padding: 3px 0; vertical-align: top; }}
            .kv-value {{ padding: 3px 0; vertical-align: top; }}
            
            .data-table {{ width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 10px; }}
            .data-table th {{ background-color: #f8f9fa; color: #2c3e50; font-weight: bold; text-align: left; padding: 6px 4px; border-bottom: 2px solid #ddd; }}
            .data-table td {{ padding: 6px 4px; border-bottom: 1px solid #eee; vertical-align: top; }}
            
            .center {{ text-align: center; }}
            .right {{ text-align: right; }}
        </style>
    </head>
    <body>
        <table style="width: 100%; border-bottom: 2px solid #eee; margin-bottom: 15px; padding-bottom: 10px;">
            <tr>
                <td style="vertical-align: top;">
                     <div class="title" style="margin-top: 0px;">EVENT ANALYSIS REPORT</div>
                     <div style="font-size: 14px; font-weight: bold; margin-top: 5px;">User: {user_info or "All Users"}</div>
                     {f'<div style="font-size: 14px; font-weight: bold; margin-top: 2px;">Type: {task_type_filter}</div>' if task_type_filter else ''}
                </td>
                <td style="text-align: right; vertical-align: top;">
                    <div style="font-size: 10px; color: #7f8c8d; margin-top: 5px;">Generated: {issue_date}</div>
                </td>
            </tr>
        </table>
        
        <div class="section-title">SUMMARY</div>
        <table class="info-grid">
            <tr>
                <td class="info-col">
                    <table class="kv-table">
                        <tr><td class="kv-key">Date Range:</td><td class="kv-value">{date_range_str}</td></tr>
                        <tr><td class="kv-key">Total Hours:</td><td class="kv-value"><strong>{report.total_hours_logged:.1f} hrs</strong></td></tr>
                        <tr><td class="kv-key">Active Events:</td><td class="kv-value">{len(report.events)}</td></tr>
                    </table>
                </td>
                <td style="width: 4%;"></td>
                <td class="info-col">
                </td>
            </tr>
        </table>
        
        <table style="width: 100%;">
            <tr>
                <td style="width: 32%; vertical-align: top;">
                    <div class="section-title">HOURS BY USER</div>
                    <table class="data-table">
                        <tr>
                            <th>User</th>
                            <th class="right">Hours</th>
                            <th class="right">%</th>
                        </tr>
                        {"".join(f'''
                        <tr>
                            <td>{u.username}</td>
                            <td class="right">{u.hours_logged:.1f}</td>
                            <td class="right">{((u.hours_logged / report.total_hours_logged) * 100) if report.total_hours_logged > 0 else 0:.1f}%</td>
                        </tr>
                        ''' for u in report.by_user) if report.by_user else '<tr><td colspan="3" class="center">No data</td></tr>'}
                    </table>
                </td>
                <td style="width: 2%;"></td>
                <td style="width: 32%; vertical-align: top;">
                    <div class="section-title">HOURS BY TYPE</div>
                    <table class="data-table">
                        <tr>
                            <th>Type</th>
                            <th class="right">Hrs</th>
                            <th class="right">%</th>
                        </tr>
                        {"".join(f'''
                        <tr>
                            <td>{t.task_type}</td>
                            <td class="right">{t.hours_logged:.1f}</td>
                            <td class="right">{((t.hours_logged / report.total_hours_logged) * 100) if report.total_hours_logged > 0 else 0:.1f}%</td>
                        </tr>
                        ''' for t in report.by_type) if report.by_type else '<tr><td colspan="3" class="center">No data</td></tr>'}
                    </table>
                </td>
                <td style="width: 2%;"></td>
                <td style="width: 32%; vertical-align: top;">
                    <div class="section-title">HOURS BY LOCATION</div>
                    <table class="data-table">
                        <tr>
                            <th>Location</th>
                            <th class="right">Hrs</th>
                            <th class="right">%</th>
                        </tr>
                        {"".join(f'''
                        <tr>
                            <td>{l.work_location}</td>
                            <td class="right">{l.hours_logged:.1f}</td>
                            <td class="right">{((l.hours_logged / report.total_hours_logged) * 100) if report.total_hours_logged > 0 else 0:.1f}%</td>
                        </tr>
                        ''' for l in report.by_location) if getattr(report, 'by_location', None) else '<tr><td colspan="3" class="center">No data</td></tr>'}
                    </table>
                </td>
            </tr>
        </table>
        
        <div class="section-title">DETAILED LOG ACTIVITY</div>
        <table class="data-table">
            <tr>
                <th style="width: 15%;">Date</th>
                <th style="width: 15%;">User</th>
                <th style="width: 35%;">Task / Description</th>
                <th style="width: 15%;">Type</th>
                <th style="width: 10%;">Location</th>
                <th class="right" style="width: 10%;">Hrs</th>
            </tr>
            {"".join(f'''
            <tr>
                <td>{e.event_date.strftime("%Y-%m-%d") if e.event_date else ""}</td>
                <td>{e.username}</td>
                <td><strong>#{e.task_id}</strong> - {e.task_description[:30] + '...' if len(e.task_description) > 30 else e.task_description}<br/><i style="color:#666;">{e.description[:40] + '...' if e.description and len(e.description)>40 else e.description or ''}</i></td>
                <td>{e.event_type}</td>
                <td>{e.work_location}</td>
                <td class="right"><strong>{e.hours_spent:.1f}</strong></td>
            </tr>
            ''' for e in report.events) if report.events else '<tr><td colspan="6" class="center" style="padding: 20px;">No event activity found in this period.</td></tr>'}
        </table>
        
    </body>
    </html>
    """
    return html_content
def generate_lead_pdf(lead) -> str:
    """Generate HTML snapshot for a Lead to be converted to PDF."""
    customer_name = lead.customer.name if lead.customer else 'No Customer Assigned'
    creator_name = lead.poc.username if lead.poc else 'Unassigned'
    issue_date = datetime.now().strftime("%Y-%m-%d %H:%M")
    desc_html = lead.description.replace('\n', '<br>') if lead.description else 'No description provided.'
    
    html_content = f"""
    <html>
    <head>
        <style>
            @page {{ size: letter portrait; margin: 1.5cm; }}
            body {{ font-family: Helvetica, Arial, sans-serif; font-size: 11px; color: #333; }}
            h1, h2, h3 {{ color: #2c3e50; margin-bottom: 5px; }}
            .title {{ font-size: 24px; font-weight: bold; color: #2980b9; margin-bottom: 5px; text-transform: uppercase; }}
            table {{ width: 100%; border-collapse: collapse; }}
            .info-grid {{ width: 100%; table-layout: fixed; margin-bottom: 20px; }}
            .info-col {{ vertical-align: top; width: 48%; padding: 15px; background-color: #f8f9fa; border-radius: 6px; border: 1px solid #e0e0e0; }}
            .kv-table td {{ padding: 6px 4px; border-bottom: 1px solid #eee; }}
            .kv-table tr:last-child td {{ border-bottom: none; }}
            .kv-key {{ font-weight: bold; color: #555; width: 40%; }}
            .kv-value {{ color: #222; text-align: right; }}
            .section-title {{ font-size: 14px; font-weight: bold; color: #fff; background-color: #2980b9; padding: 6px 10px; margin-top: 20px; margin-bottom: 10px; border-radius: 4px; }}
            .desc-box {{ background-color: #f8f9fa; border: 1px solid #e0e0e0; padding: 15px; border-radius: 6px; font-size: 12px; line-height: 1.5; margin-bottom: 20px; }}
        </style>
    </head>
    <body>
        <table style="width: 100%; border-bottom: 2px solid #eee; margin-bottom: 15px; padding-bottom: 10px;">
            <tr>
                <td style="vertical-align: top;">
                     <div class="title" style="margin-top: 0px;">NEW LEAD SUMMARY</div>
                     <div style="font-size: 16px; font-weight: bold; margin-top: 5px;">L-{lead.id}: {lead.name}</div>
                </td>
                <td style="text-align: right; vertical-align: top;">
                    <div style="font-size: 10px; color: #7f8c8d; margin-top: 5px;">Generated: {issue_date}</div>
                </td>
            </tr>
        </table>

        <!-- Overview Section -->
        <table class="info-grid">
            <tr>
                <td class="info-col">
                    <table class="kv-table">
                        <tr><td class="kv-key">Status:</td><td class="kv-value" style="text-transform: capitalize;"><strong>{lead.status.value if hasattr(lead.status, 'value') else str(lead.status).replace('LeadStatus.', '')}</strong></td></tr>
                        <tr><td class="kv-key">Customer:</td><td class="kv-value">{customer_name}</td></tr>
                        <tr><td class="kv-key">Location/Company:</td><td class="kv-value">{lead.location.name if getattr(lead, 'location', None) else (lead.company or '-')}</td></tr>
                        <tr><td class="kv-key">Created By:</td><td class="kv-value">{creator_name}</td></tr>
                    </table>
                </td>
                <td style="width: 4%;"></td>
                <td class="info-col">
                    <table class="kv-table">
                        <tr><td class="kv-key">Date Created:</td><td class="kv-value">{lead.created_at.strftime("%Y-%m-%d") if lead.created_at else '-'}</td></tr>
                        <tr><td class="kv-key">Target Due Date:</td><td class="kv-value">{lead.due_date.strftime("%Y-%m-%d") if lead.due_date else 'TBD'}</td></tr>
                        <tr><td class="kv-key">Estimated Value:</td><td class="kv-value">{f"${lead.estimated_value:,.2f}" if lead.estimated_value else '-'}</td></tr>
                        <tr><td class="kv-key">Email:</td><td class="kv-value">{lead.email or '-'}</td></tr>
                    </table>
                </td>
            </tr>
        </table>

        <div class="section-title">DESCRIPTION</div>
        <div class="desc-box">
            {desc_html}
        </div>
        
    </body>
    </html>
    """
    return html_content
